package com.google.gson.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.$Gson$Types;
import java.lang.reflect.Type;
import org.junit.jupiter.api.Test;

class TypeTokenTest {

  @Test
  void testGetArray_withClassComponentType() {
    Type componentType = String.class;
    TypeToken<?> result = TypeToken.getArray(componentType);
    assertNotNull(result);
    assertTrue(result.getType().getTypeName().startsWith("[L"));
    assertEquals(Object[].class.isAssignableFrom((Class<?>) result.getRawType()) || result.getRawType().isArray(), true);
  }

  @Test
  void testGetArray_withParameterizedTypeComponent() {
    Type componentType = mock(Type.class);
    TypeToken<?> spyTypeToken = spy(new TypeToken<String[]>() {});
    // Because $Gson$Types.arrayOf is static and final, we cannot mock it easily without PowerMock.
    // So we just test the returned TypeToken is not null and the type is an array type.
    TypeToken<?> result = TypeToken.getArray(componentType);
    assertNotNull(result);
    assertNotNull(result.getType());
  }

  @Test
  void testGetArray_withGenericArrayTypeComponent() {
    Type genericArrayType = mock(Type.class);
    TypeToken<?> result = TypeToken.getArray(genericArrayType);
    assertNotNull(result);
    assertNotNull(result.getType());
  }
}
